        // which changes the generic type from `String` to `Object`, breaking semantic equivalence.
        // The DSL engine's implicit type inference validation must prevent this transformation.
        Object expr = new ArrayList<String>();

        // Anonymous classes cannot use the diamond operator (Java language restriction).
        // This pattern `new $Type<$Exprs$>()` does not match anonymous classes so it won't apply anyway.
